export class AddTeamTypeToTeamsTable1755751712591
  implements MigrationInterface
{
  public async up(queryRunner: QueryRunner): Promise<void> {
    // Add team_type column with default 'multiple'
    await queryRunner.addColumn(
      'teams',
      new TableColumn({
        name: 'team_type',
        type: 'varchar',
        length: '32',
        default: "'multiple'",
      }),
    );

    // Update team_type to 'single' for teams with single personal_user
    await queryRunner.query(`
      UPDATE teams t
      SET team_type = 'single'
      WHERE EXISTS (
        SELECT 1
        FROM user_roles ur
        JOIN role_groups rg ON ur.role_group_id = rg.id
        WHERE ur.team_id = t.id
        GROUP BY ur.team_id
        HAVING COUNT(DISTINCT ur.user_id) = 1
          AND MAX(rg.name) = 'personal_user'
      )
    `);
  }

  public async down(queryRunner: QueryRunner): Promise<void> {
    await queryRunner.dropColumn('teams', 'team_type');
  }
}

