import { HttpService } from '@nestjs/axios';
import { CacheModule } from '@nestjs/cache-manager';
import { INestApplication } from '@nestjs/common';
import { Test } from '@nestjs/testing';
import _ from 'lodash';
import request from 'supertest';
import { DataSource } from 'typeorm';

import { DataUtil } from '@/app/common/utils/data.util';
import { StringUtil } from '@/app/common/utils/string.util';
import { User } from '@/app/models/user';
import { UserRole } from '@/app/models/user-role';
import { AppModule } from '@/app/modules/app.module';
import { TeamPlansPersistence } from '@/app/persistence/team-plans.persistense';
import { TeamsPersistence } from '@/app/persistence/teams.persistence';
import { UsersPersistence } from '@/app/persistence/users.persistence';
import { CognitoProvider } from '@/app/providers/cognito.provider';
import { ConfigProvider } from '@/app/providers/config.provider';
import { EmailProvider } from '@/app/providers/email.provider';
import { I18nProvider } from '@/app/providers/i18n.provider';
import { StorageProvider } from '@/app/providers/storage.provider';
import { UserData, users } from '@/database/seeding/generators/data/users';
import { DataUtil as TestDataUtil } from '@/database/seeding/generators/utils/data.util';
import { TestUtil } from '@test/app/test-utils/test.util';
import {
  invitation1HtmlEn,
  invitation1HtmlJa,
  invitation2HtmlEn,
  invitation2HtmlJa,
} from '@test/data/email/invitations';
import { usersResultForGet, usersResultForSearch } from '@test/data/team-users';

const userFinder = TestDataUtil.getFinder(users);

describe('User(Team)', () => {
  let app: INestApplication;
  let usersPersistence: UsersPersistence;
  let configProvider: ConfigProvider;
  let cognitoProvider: CognitoProvider;
  let httpService: HttpService;
  let dataSource: DataSource;

  beforeAll(async () => {
    const moduleRef = await Test.createTestingModule({
      imports: [AppModule, CacheModule.register()],
      providers: [
        TeamsPersistence,
        TeamPlansPersistence,
        UsersPersistence,
        StorageProvider,
        EmailProvider,
        I18nProvider,
      ],
    }).compile();
    app = moduleRef.createNestApplication();

    usersPersistence = moduleRef.get<UsersPersistence>(UsersPersistence);
    configProvider = moduleRef.get<ConfigProvider>(ConfigProvider);
    cognitoProvider = moduleRef.get<CognitoProvider>(CognitoProvider);
    httpService = moduleRef.get<HttpService>(HttpService);
    await I18nProvider.loadResources();
    dataSource = await TestUtil.getDataSource(configProvider.config);

    await app.init();
  });

  beforeEach(async () => {
    jest.clearAllMocks();
  });

  it(`Search users`, () => {
    const user = userFinder.getByTag('a_admin-1');
    const userId = user.id;
    const teamId = user.team_id;
    return request(app.getHttpServer())
      .post(`/api/teams/${teamId}/users/search`)
      .set({
        Authorization: userId,
        'X-Api-Version': `${TestUtil.getApiTestVersion()}`,
      })
      .send({
        orderBy: 'id',
        isOrderDesc: false,
      })
      .expect(201)
      .expect((res) => {
        const body = DataUtil.omitDeep(res.body, ['updatedAt', 'createdAt']);
        expect(body).toMatchObject(usersResultForSearch);

        // Redundant but a fail safe when usersResultForSearch collapsed.
        body.users.forEach((user) => {
          expect(user.teams.some(team => team.id === teamId)).toBe(true);
        });
      });
  });

  it(`Get user`, () => {
    const user = userFinder.getByTag('a_admin-1');
    const targetUser = userFinder.getByTag('a_member-1');
    const userId = user.id;

